#include <iostream>
#include <vector>
using namespace std;

int findMin(vector<int>& nums) {
    int low = 0, high = nums.size() - 1;
    while (low <= high) {
        int mid = (low + high) / 2;
        if (nums[mid] > nums[high])
            low = mid + 1;
        else if (nums[mid] < nums[high])
            high = mid;
        else
            high -= 1;
    }
    return nums[low];
}

int main() {
    vector<int> nums = {4, 5, 6, 7, 3, 1, 2};
    cout << findMin(nums) << endl;
    return 0;
}
